#include <iostream>

template <typename T, int N>
class FixedBuffer {
    T data_[N]{};
public:
    void set(int index, T value) { data_[index] = value; }
    T get(int index) const { return data_[index]; }
    int size() const { return N; }
};

int main() {
    FixedBuffer<int, 5> buf;

    for (int i = 0; i < buf.size(); ++i) {
        int v;
        std::cin >> v;
        buf.set(i, v);
    }

    int total = 0;
    for (int i = 0; i < buf.size(); ++i)
        total += buf.get(i);

    std::cout << "Sum: " << total << "\n";
    return 0;
}

