#include <iostream>
#include <cassert>

template <typename T, int N>
class FixedArray {
    T data_[N]{};
public:
    T& operator[](int i) { assert(i >= 0 && i < N); return data_[i]; }
    const T& operator[](int i) const { assert(i >= 0 && i < N); return data_[i]; }
    int size() const { return N; }
};

void findMinMax(const FixedArray<int, 4>& arr, int& minVal, int& maxVal) {
    minVal = arr[0];
    maxVal = arr[0];
    for (int i = 1; i < arr.size(); ++i) {
        if (arr[i] < minVal) minVal = arr[i];
        if (arr[i] > maxVal) maxVal = arr[i];
    }
}

int main() {
    FixedArray<int, 4> arr;
    for (int i = 0; i < arr.size(); ++i)
        std::cin >> arr[i];

    int mn, mx;
    findMinMax(arr, mn, mx);
    std::cout << "Min: " << mn << "\n";
    std::cout << "Max: " << mx << "\n";
    return 0;
}
